"""
內嵌圖示資料模組
自動生成於圖片: branch.ico
"""

import base64
from PyQt6.QtGui import QIcon, QPixmap

# Base64 編碼的圖示資料
BRANCH_ICON_DATA = """

"""

def get_branch_icon():
    """返回 branch 圖示"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(BRANCH_ICON_DATA))
    return QIcon(pixmap)

def get_branch_pixmap():
    """返回 branch 像素圖"""
    pixmap = QPixmap()
    pixmap.loadFromData(base64.b64decode(BRANCH_ICON_DATA))
    return pixmap

